h2-sdk-configuration-p5f308966.translation:
```typescript showLineNumbers
import { adapty } from 'react-native-adapty';
import { Mixpanel } from 'mixpanel-react-native';

// Если в вашем приложении уже есть общий экземпляр Mixpanel, используйте его.
const trackAutomaticEvents = true;
const mixpanel = new Mixpanel('YOUR_PROJECT_TOKEN', trackAutomaticEvents);
await mixpanel.init();

// Это текущий distinct_id Mixpanel (генерируется автоматически или задаётся через mixpanel.identify(...))
const mixpanelUserId = await mixpanel.getDistinctId();

try {
    await adapty.setIntegrationIdentifier("mixpanel_user_id", mixpanelUserId);
} catch (error) {
    // обработайте `AdaptyError`
}
```
